mapper.update:
update jst_rebate_settlement
set status = #{targetStatus},
    update_by = #{updateBy},
    update_time = #{updateTime}
where settlement_id = #{settlementId}
  and channel_id = #{channelId}
  and status = #{expectedStatus}
  and del_flag = '0'

mapper.select:
select rs.settlement_id as settlementId, rs.settlement_no as settlementNo, rs.apply_amount as applyAmount, rs.negative_offset_amount as negativeOffsetAmount, rs.actual_pay_amount as actualPayAmount, rs.status as status, rs.invoice_status as invoiceStatus, rs.apply_time as applyTime, rs.update_time as updateTime, (select count(1) from jst_rebate_ledger rl where rl.settlement_id = rs.settlement_id) as ledgerCount, ctr.contract_no as contractNo from jst_rebate_settlement rs left join jst_contract_record ctr on ctr.ref_settlement_id = rs.settlement_id and ctr.target_type = 'channel' and ctr.del_flag = '0' where rs.channel_id = #{channelId} and rs.del_flag = '0'
and rs.status = #{status}
order by rs.apply_time desc, rs.settlement_id desc

select rs.settlement_id, rs.settlement_no, rs.channel_id, c.channel_name, rs.apply_amount, rs.negative_offset_amount, rs.actual_pay_amount, rs.status, rs.invoice_status, rs.apply_time, rs.pay_time, rs.update_time from jst_rebate_settlement rs left join jst_channel c on c.channel_id = rs.channel_id and c.del_flag = '0' where rs.del_flag = '0'
and rs.channel_id = #{channelId}
and rs.status = #{status}
order by rs.apply_time desc, rs.settlement_id desc

mapper.update:
update jst_rebate_settlement
set status = 'approved',
    negative_offset_amount = #{negativeOffsetAmount},
    actual_pay_amount = #{actualPayAmount},
    audit_remark = #{auditRemark},
    update_by = #{updateBy},
    update_time = #{updateTime}
where settlement_id = #{settlementId}
  and status = #{expectedStatus}
  and del_flag = '0'

update jst_rebate_settlement
set status = 'rejected',
    audit_remark = #{auditRemark},
    update_by = #{updateBy},
    update_time = #{updateTime}
where settlement_id = #{settlementId}
  and status = #{expectedStatus}
  and del_flag = '0'

update jst_rebate_settlement
set status = 'paid',
    pay_voucher_url = #{payVoucherUrl},
    pay_time = #{payTime},
    update_by = #{updateBy},
    update_time = #{updateTime}
where settlement_id = #{settlementId}
  and status = #{expectedStatus}
  and del_flag = '0'
